export function getOracaoGuiadaDoDia() {
  const hoje = new Date();
  const diaDoAno = Math.floor(
    (hoje - new Date(hoje.getFullYear(), 0, 0)) / (1000 * 60 * 60 * 24)
  );
  const index = diaDoAno % ORACOES_GUIADAS.length;
  return ORACOES_GUIADAS[index];
}
